import org.xml.sax.InputSource;
import org.xml.sax.SAXException;

import javax.xml.XMLConstants;
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.parsers.ParserConfigurationException;
import javax.xml.transform.Source;
import javax.xml.transform.stream.StreamSource;
import javax.xml.validation.Schema;
import javax.xml.validation.SchemaFactory;
import javax.xml.validation.Validator;
import java.io.StringReader;

/**
 * XML Processing Service
 * Provides functionality for loading and validating XML schemas
 */
public class XmlProcessingService {

    /**
     * Loads and validates an XML Schema from string content
     * 
     * @param schemaContent The XSD schema content as a string
     * @throws Exception if schema parsing or validation fails
     */
    public void loadSchema(String schemaContent) throws Exception {
        if (schemaContent == null || schemaContent.trim().isEmpty()) {
            throw new IllegalArgumentException("Schema content cannot be null or empty");
        }

        try {
            // Create SchemaFactory with W3C XML Schema specification
            SchemaFactory schemaFactory = SchemaFactory.newInstance(XMLConstants.W3C_XML_SCHEMA_NS_URI);

            // Disable external entity processing for security
            schemaFactory.setProperty(XMLConstants.ACCESS_EXTERNAL_DTD, "");
            schemaFactory.setProperty(XMLConstants.ACCESS_EXTERNAL_SCHEMA, "");

            // Convert string content to Source
            Source schemaSource = new StreamSource(new java.io.StringReader(schemaContent));

            // Load and compile the schema
            Schema schema = schemaFactory.newSchema(schemaSource);

            // Optional: Validate the schema itself by creating a validator
            // This ensures the schema is not only parsed but also valid
            Validator validator = schema.newValidator();

        } catch (SAXException e) {
            // Schema is not valid according to XSD specifications
            throw new Exception("Invalid XML Schema: " + e.getMessage(), e);
        } catch (Exception e) {
            // Handle other potential exceptions (security, configuration, etc.)
            throw new Exception("Failed to load XML Schema: " + e.getMessage(), e);
        }
    }
}

